import React, { useCallback, useState } from 'react';
import { Button, DocumentHistoryModal, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../store/hooks';
import { erpDocumentHistoryClient } from '../../config/documentHistoryClients';

export interface CatalogDocumentHistoryProps {
  testIdPrefix: string;
  documentType: string;
  documentId?: string;
  documentCode?: string;
  variant?: 'button' | 'inline';
  isOpen?: boolean;
  onClose?: () => void;
}

export const CatalogDocumentHistory: React.FC<CatalogDocumentHistoryProps> = ({
  testIdPrefix,
  documentType,
  documentId,
  documentCode,
  variant = 'inline',
  isOpen: controlledOpen,
  onClose: controlledOnClose,
}) => {
  const dispatch = useAppDispatch();
  const [internalOpen, setInternalOpen] = useState(false);
  const isControlled = controlledOpen !== undefined;
  const isOpen = isControlled ? controlledOpen : internalOpen;
  const onClose = useCallback(() => {
    if (isControlled) controlledOnClose?.();
    else setInternalOpen(false);
  }, [controlledOnClose, isControlled]);

  const onError = useCallback(
    (message: string) => dispatchAppToast(dispatch, { message, type: 'error' }),
    [dispatch],
  );

  if (!documentId) return null;

  return (
    <>
      {variant === 'inline' && !isControlled && (
        <Button
          variant="secondary"
          size="sm"
          data-testid={`${testIdPrefix}-history-btn`}
          onClick={() => setInternalOpen(true)}
        >
          <i className="fas fa-history" /> Lịch sử
        </Button>
      )}
      <DocumentHistoryModal
        isOpen={isOpen}
        onClose={onClose}
        client={erpDocumentHistoryClient}
        documentType={documentType}
        documentId={documentId}
        documentCode={documentCode}
        testIdPrefix={testIdPrefix}
        onError={onError}
      />
    </>
  );
};
